@router.post("/evaluate", response_model=EvalResponse)
async def evaluate_prompt(
    request: EvalRequest,
    mlflow: MLflowClient = Depends(get_mlflow),
    judge: JudgeService = Depends(get_judge),
):
    run = mlflow.create_run(request.experiment_id)
    scores = await judge.score(request.prompt, request.response, request.criteria)
    for name, value in scores.items():
        mlflow.log_metric(run.info.run_id, name, value)
    mlflow.set_terminated(run.info.run_id)
    return EvalResponse(run_id=run.info.run_id, scores=scores)

