class JWTAuthMiddleware:
    def __init__(self, app, secret_key: str, algorithm: str = "HS256", exclude_paths: list[str] = None):
        self.app = app
        self.secret_key = secret_key
        self.algorithm = algorithm
        self.exclude_paths = exclude_paths or ["/health", "/docs", "/openapi.json"]

    async def __call__(self, scope, receive, send):
        if scope["type"] != "http":
            return await self.app(scope, receive, send)
        path = scope["path"]
        if any(path.startswith(ep) for ep in self.exclude_paths):
            return await self.app(scope, receive, send)
        token = self._extract_token(scope)
        if not token or not self._validate_token(token):
            return await self._send_401(send)
        scope["state"] = {"user": self._decode_token(token)}
        return await self.app(scope, receive, send)
